function extractTextFromHtml(n){const t=document.createElement("div");return t.innerHTML=n,(t.textContent||t.innerText||"").trim()}function speak(n,t){if("speechSynthesis"in window){const i=new SpeechSynthesisUtterance(n);return i.onend=()=>{t.invokeMethodAsync("OnSpeechEnd")},i.onerror=()=>{t.invokeMethodAsync("OnSpeechEnd")},window.speechSynthesis.speak(i),window.speechSynthesisInterop.currentUtterance=i,Promise.resolve(!0)}return Promise.resolve(!1)}function cancel(){"speechSynthesis"in window&&(window.speechSynthesis.cancel(),window.speechSynthesisInterop.currentUtterance=null)}window.speechSynthesisInterop=window.speechSynthesisInterop||{}